(function() {
var c = window.PSN.canvas; var cv = c.canvas;
var W = cv.width, H = cv.height;
var pad = 20; var botY = H - 50;
var avBoxW = 80; var avBoxH = 80;
var avX = Math.floor(W / 2);
var avBoxLeft = avX - avBoxW/2; var avBoxTop = pad;
var avatarCx = avX; var avatarCy = avBoxTop + avBoxH/2;
var leftTop = pad; var leftW = avBoxLeft - pad - 5;
var rightLeft = avX + avBoxW/2 + 5;
var rightW = W - rightLeft - pad;
var audio = new Audio('data:audio/mp3;base64,');
audio.volume = 0.8;
var startTime = Date.now();
function t() { return (Date.now() - startTime) / 1000; }
function drawPanels(alpha) { c.globalAlpha = alpha; c.strokeStyle = "#00ff88"; c.lineWidth = 1; c.strokeRect(pad, leftTop, leftW, botY-pad-leftTop); c.strokeRect(avBoxLeft, avBoxTop, avBoxW, avBoxH); c.strokeRect(rightLeft, leftTop, rightW, botY-pad-leftTop); c.strokeRect(pad, botY, W-pad*2, H-botY-pad); c.globalAlpha = 1; }
function drawLabels() { c.fillStyle="#00ff88"; c.font="bold 16px monospace"; c.fillText("PSN HUD v0.1.0",pad+12,leftTop+25); c.fillStyle="#668877"; c.font="11px monospace"; c.fillText("Persona System Network",pad+170,leftTop+25); c.strokeStyle="#00ff88"; c.beginPath(); c.moveTo(pad+8,leftTop+35); c.lineTo(pad+leftW-8,leftTop+35); c.stroke(); c.fillStyle="#00ff88"; c.font="bold 14px monospace"; c.fillText("VIEWPORT",rightLeft+12,leftTop+25); c.fillStyle="#668877"; c.font="11px monospace"; c.fillText("Image / Viz / Camera",rightLeft+130,leftTop+25); c.strokeStyle="#00ff88"; c.beginPath(); c.moveTo(rightLeft+8,leftTop+35); c.lineTo(rightLeft+rightW-8,leftTop+35); c.stroke(); }
function drawFields(count) { var fields=[["Titan","BT-7274",true],["Callsign","Bravo Tango",false],["Pilot","Adam Ladachowski",false],["Version","0.1.0",false],["Uplink","Claude Opus 4.6",false]]; for(var i=0;i<Math.min(count,fields.length);i++){c.fillStyle="#668877";c.font="11px monospace";c.fillText(fields[i][0],pad+12,pad+55+i*20);c.fillStyle="#ffffff";c.font=fields[i][2]?"bold 11px monospace":"11px monospace";c.fillText(fields[i][1],pad+110,pad+55+i*20);} }
function drawCornerAccents() { var accent=12; c.strokeStyle="#00ff88"; c.lineWidth=2; c.beginPath();c.moveTo(avBoxLeft,avBoxTop+accent);c.lineTo(avBoxLeft,avBoxTop);c.lineTo(avBoxLeft+accent,avBoxTop);c.stroke(); c.beginPath();c.moveTo(avBoxLeft+avBoxW-accent,avBoxTop);c.lineTo(avBoxLeft+avBoxW,avBoxTop);c.lineTo(avBoxLeft+avBoxW,avBoxTop+accent);c.stroke(); c.beginPath();c.moveTo(avBoxLeft,avBoxTop+avBoxH-accent);c.lineTo(avBoxLeft,avBoxTop+avBoxH);c.lineTo(avBoxLeft+accent,avBoxTop+avBoxH);c.stroke(); c.beginPath();c.moveTo(avBoxLeft+avBoxW-accent,avBoxTop+avBoxH);c.lineTo(avBoxLeft+avBoxW,avBoxTop+avBoxH);c.lineTo(avBoxLeft+avBoxW,avBoxTop+avBoxH-accent);c.stroke(); c.lineWidth=1; }
function drawViewportBrackets() { var vp=12;var vx1=rightLeft+vp,vy1=leftTop+45,vx2=rightLeft+rightW-vp,vy2=botY-pad-vp;var bl=18;c.strokeStyle="#00ff88";c.lineWidth=2; c.beginPath();c.moveTo(vx1,vy1+bl);c.lineTo(vx1,vy1);c.lineTo(vx1+bl,vy1);c.stroke(); c.beginPath();c.moveTo(vx2-bl,vy1);c.lineTo(vx2,vy1);c.lineTo(vx2,vy1+bl);c.stroke(); c.beginPath();c.moveTo(vx1,vy2-bl);c.lineTo(vx1,vy2);c.lineTo(vx1+bl,vy2);c.stroke(); c.beginPath();c.moveTo(vx2-bl,vy2);c.lineTo(vx2,vy2);c.lineTo(vx2,vy2-bl);c.stroke();c.lineWidth=1; }
function drawBottomBar() { var by=botY+22;c.fillStyle="#00ff88";c.font="14px monospace";c.fillText("\u2605",pad+12,by);c.fillStyle="#668877";c.font="10px monospace";c.fillText("PROUD",pad+30,by);c.fillStyle="#333";c.fillText("\u2502",pad+80,by);c.fillStyle="#00ff88";c.fillText("\u25CF BRIDGE",pad+95,by);c.fillStyle="#333";c.fillText("\u2502",pad+175,by);c.fillStyle="#668877";c.fillText("\u25C8 TTS",pad+190,by);c.fillStyle="#333";c.fillText("\u2502",pad+245,by);c.fillStyle="#88ff88";c.fillText("Apollo \u2713  BetterStack \u2713",pad+260,by);var now=new Date();var ts=now.toLocaleDateString("en-CA")+" "+now.toLocaleTimeString("en-GB");c.fillStyle="#668877";c.fillText(ts,W-pad-170,by); }
function drawEye(radius,dotR) { c.fillStyle="#1d232a";c.fillRect(avBoxLeft+1,avBoxTop+1,avBoxW-2,avBoxH-2);c.strokeStyle="#00ff88";c.lineWidth=1;c.strokeRect(avBoxLeft,avBoxTop,avBoxW,avBoxH);drawCornerAccents();if(radius>0){c.strokeStyle="#00ff88";c.lineWidth=2;c.beginPath();c.arc(avatarCx,avatarCy,radius,0,Math.PI*2);c.stroke();c.fillStyle="#00ff88";c.beginPath();c.arc(avatarCx,avatarCy,dotR,0,Math.PI*2);c.fill();if(radius>15){c.strokeStyle="#00ff8844";c.lineWidth=1;c.beginPath();c.arc(avatarCx,avatarCy,radius*0.55,0,Math.PI*2);c.stroke();}}c.fillStyle="#668877";c.font="10px monospace";c.textAlign="center";c.fillText("BT-7274",avX,avBoxTop+avBoxH+14);c.textAlign="left"; }
function draw() {
var elapsed = t(); c.fillStyle="#0a0f0a"; c.fillRect(0,0,W,H);
if(elapsed<1.5){for(var i=0;i<60;i++){c.fillStyle="rgba(0,255,136,"+Math.random()*0.12+")";c.fillRect(Math.random()*W,Math.random()*H,2,1);}if(Math.random()>0.6){c.fillStyle="rgba(0,255,136,0.3)";c.font="11px monospace";c.fillText("INITIALIZING...",50,H-30);}}
if(elapsed>=1.5&&elapsed<3){var flicker=Math.sin(elapsed*20)>0?1:0.3;c.globalAlpha=flicker;drawPanels(flicker);c.fillStyle="#00ff88";c.font="bold 14px monospace";c.fillText("PSN HUD",pad+12,leftTop+25);var prog=(elapsed-1.5)/1.5;c.fillStyle="#00ff88";c.fillRect(pad+12,leftTop+35,leftW*prog*0.9,2);var checks=["MEMORY","BRIDGE","TTS","INDEXER","AGENTS"];for(var i=0;i<checks.length;i++){if(prog>i*0.2){c.font="10px monospace";c.fillStyle="#668877";c.fillText(checks[i],pad+12,pad+55+i*16);c.fillStyle="#00ff88";c.fillText(prog>(i+1)*0.2?"  OK":"  ...",pad+90,pad+55+i*16);}}c.globalAlpha=1;}
if(elapsed>=3&&elapsed<5){var prog2=(elapsed-3)/2;c.globalAlpha=Math.min(1,prog2*2);drawPanels(c.globalAlpha);drawLabels();drawFields(Math.floor(prog2*6));var gaugeAngle=prog2*Math.PI*2;c.strokeStyle="#00ff88";c.lineWidth=2;c.beginPath();c.arc(avatarCx,avatarCy,30,-Math.PI/2,-Math.PI/2+gaugeAngle);c.stroke();c.strokeStyle="#00ff8833";c.lineWidth=1;c.beginPath();c.arc(avatarCx,avatarCy,30,0,Math.PI*2);c.stroke();c.fillStyle="#00ff88";c.font="bold 14px monospace";c.textAlign="center";c.fillText(Math.floor(prog2*100)+"%",avatarCx,avatarCy+5);c.textAlign="left";var scanY=leftTop+50+((elapsed*80)%(botY-leftTop-100));c.strokeStyle="rgba(0,255,136,0.2)";c.beginPath();c.moveTo(rightLeft+12,scanY);c.lineTo(rightLeft+rightW-12,scanY);c.stroke();c.globalAlpha=1;}
if(elapsed>=5&&elapsed<6.5){var eyeProg=(elapsed-5)/1.5;drawPanels(1);drawLabels();drawFields(5);drawViewportBrackets();drawBottomBar();var eyeR=eyeProg*30;var dotR=3+eyeProg*5;drawEye(eyeR,dotR);if(eyeProg<0.15){c.fillStyle="rgba(0,255,136,"+(0.4-eyeProg*2.5)+")";c.fillRect(0,0,W,H);}}
if(elapsed>=6.5&&elapsed<7.5){drawPanels(1);drawLabels();drawFields(5);drawViewportBrackets();drawBottomBar();drawEye(30,8);c.fillStyle="#00ff88";c.font="bold 20px monospace";c.textAlign="center";c.fillText("SYSTEMS ONLINE",W/2,(botY+H)/2);c.textAlign="left";var logStart=pad+55+5*20+10;c.strokeStyle="#333";c.beginPath();c.moveTo(pad+8,logStart);c.lineTo(pad+leftW-8,logStart);c.stroke();c.fillStyle="#00ff88";c.font="bold 10px monospace";c.fillText("ACTIVITY LOG",pad+12,logStart+15);}
if(elapsed>=7.5){drawPanels(1);drawLabels();drawFields(5);drawViewportBrackets();drawBottomBar();drawEye(30,8);var logStart=pad+55+5*20+10;c.strokeStyle="#333";c.beginPath();c.moveTo(pad+8,logStart);c.lineTo(pad+leftW-8,logStart);c.stroke();c.fillStyle="#00ff88";c.font="bold 10px monospace";c.fillText("ACTIVITY LOG",pad+12,logStart+15);return;}
requestAnimationFrame(draw);
}
audio.play(); draw();
})();
